 haut volcan de l'\u00eele.","Descriptif":"Situ\u00e9e \u00e0 mi-chemin entre Saint-Philippe et Saint-Joseph, sur les versants bois\u00e9s du volcan, la ferme auberge Desprairies propose 6 chambres toutes \u00e9quip\u00e9es, au c\u0153ur d'une v\u00e9g\u00e9tation tropicale, et une salle de restauration (sur commande). Petit d\u00e9jeuner inclus dans la nuit\u00e9e. Les l\u00e9gumes ainsi que les viandes viennent de la ferme qui adh\u00e8re au r\u00e9seau Bienvenue \u00e0 la Ferme. Productions de la ferme : \u00e9levage divers, mara\u00eechage et fruits oubli\u00e9s, palmiste.  \nSp\u00e9cialit\u00e9s: feuillet\u00e9s de palmiste, canard fum\u00e9 aux petits l\u00e9gumes, mousse de patate douce ou manioc avec coulis de goyavier. Tarif: adulte : 20 \u20ac, enfant (moins de 10 ans) : 10 \u20ac et enfant (moins de 5 ans) : 5 \u20ac.","Descriptif du plan d'acc\u00e8s":"En venant de l'Est : 2 km apr\u00e8s la sortie de Basse Vall\u00e9e, prendre la D37 sur la droite et suivre les panneaux directionnels. En venant du Sud : 200 m apr\u00e8s panneau d'agglom\u00e9ration de Vincendo, prendre la D37 et suivre les panneaux directionnels.","Jours et horaires d'ouverture":"","Labels":"Bienvenue \u00e0 la ferme","Date de cr\u00e9ation - Etablissement":"","Date de fermeture":"","Fournisseur - Nom":"Mr Willy Desprairies","Fournisseur - SIRET":"42181946700018","Fournisseur - adresse":"Mr Willy Desprairies: 44 Chemin Matouta, 97480 Saint-Joseph - Matouta","Fournisseur - contacts":"matouta@wanadoo.fr / 0262372027","Fournisseur - date de cr\u00e9ation":"","Fournisseur - Code postal":"","Fournisseur - Bureau":"","Fournisseur - Code NAF":"","Fournisseur - Chambre consulaire":"","Fournisseur - Forme juridique":"","Fournisseur - CFE":"","Nb Produits":"","Coordonn\u00e9es GPS":"-21.360783, 55.700915","Liste URL moteur":"","Tarif Montant":"","Tarif libell\u00e9":"","Num taxe de s\u00e9jour":"","Descriptif OTI":"","Accroche OTI":"","Status":"","commentaire":"","Date de derniere modification":"","Colones modifi\u00e9es":"","Aire d'adh\u00e9sion":"AD2R"}}]$old_data_review_rows$::jsonb) AS r(item);

WITH mapped AS (
    SELECT
        raw_source_data,
        mapping_review_reason,
        CASE
            WHEN raw_source_data->>U&'Nom cat\00E9gorie' = 'Auberge'
             AND lower(COALESCE(raw_source_data->>U&'Nom sous cat\00E9gorie', '')) LIKE '%chambre%'
                THEN 'HLO'
            WHEN raw_source_data->>U&'Nom cat\00E9gorie' = 'Auberge'
                THEN 'RES'
            WHEN raw_source_data->>U&'Nom cat\00E9gorie' IN ('Terre', U&'Etangs et rivi\00E8res', U&'Etangs et rivi\00E8res ; Mer')
                THEN 'ACT'
            WHEN raw_source_data->>U&'Nom cat\00E9gorie' IN (U&'Patrimoine naturel', 'Divertissement')
                THEN 'LOI'
            WHEN COALESCE(raw_source_data->>U&'Nom cat\00E9gorie', '') = ''
             AND lower(COALESCE(raw_source_data->>'Nom commercial', '')) LIKE '%boutik%'
                THEN 'COM'
            ELSE 'LOI'
        END AS object_type
    FROM old_data_review_raw
)
INSERT INTO staging.object_temp (
    import_batch_id,
    staging_object_key,
    source_sheet,
    raw_source_data,
    object_type,
    name,
    external_id,
    source_org_object_id,
    region_code,
    status,
    commercial_visibility,
    extra,
    deduplication_status,
    resolution_status,
    is_approved
)
SELECT
    'old-data-berta2-all-20260501-01',
    raw_source_data->>'id',
    'Berta 2.0',
    raw_source_data,
    object_type,
    NULLIF(btrim(raw_source_data->>'Nom commercial'), ''),
    raw_source_data->>'id',
    NULL,
    'RUN',
    CASE lower(COALESCE(raw_source_data->>'En ligne', ''))
        WHEN 'oui' THEN 'published'
        ELSE 'draft'
    END,
    'active',
    jsonb_build_object(
        'legacy_object_id', raw_source_data->>'id',
        'source_category', raw_source_data->>U&'Nom cat\00E9gorie',
        'source_subcategory', raw_source_data->>U&'Nom sous cat\00E9gorie',
        'source_group_category', raw_source_data->>U&'Groupe cat\00E9gorie',
        'source_zone', raw_source_data->>'Zone',
        'source_status', raw_source_data->>'Status',
        'mapping_review_required', true,
        'mapping_review_reason', mapping_review_reason,
        'provisional_object_type', object_type
    ),
    'pending',
    'pending',
    TRUE
FROM mapped;

WITH loc AS (
    SELECT
        raw_source_data,
        NULLIF(btrim(raw_source_data->>U&'Coordonn\00E9es GPS'), '') AS gps
    FROM old_data_review_raw
)
INSERT INTO staging.object_location_temp (
    import_batch_id,
    staging_object_key,
    address1,
    postcode,
    city,
    lieu_dit,
    direction,
    latitude,
    longitude,
    is_main_location,
    source_sheet,
    raw_source_data,
    resolution_status,
    is_approved
)
SELECT
    'old-data-berta2-all-20260501-01',
    raw_source_data->>'id',
    NULLIF(btrim(raw_source_data->>'Adresse'), ''),
    NULLIF(btrim(raw_source_data->>'Code postal'), ''),
    NULLIF(btrim(raw_source_data->>'Bureau postal'), ''),
    NULLIF(btrim(raw_source_data->>'Lieux-dits'), ''),
    NULLIF(btrim(raw_source_data->>U&'Descriptif du plan d''acc\00E8s'), ''),
    CASE
        WHEN gps ~ '^\s*-?[0-9]+(\.[0-9]+)?\s*,\s*-?[0-9]+(\.[0-9]+)?\s*$'
        THEN split_part(regexp_replace(gps, '\s+', '', 'g'), ',', 1)::numeric
        ELSE NULL
    END,
    CASE
        WHEN gps ~ '^\s*-?[0-9]+(\.[0-9]+)?\s*,\s*-?[0-9]+(\.[0-9]+)?\s*$'
        THEN split_part(regexp_replace(gps, '\s+', '', 'g'), ',', 2)::numeric
        ELSE NULL
    END,
    TRUE,
    'Berta 2.0',
    raw_source_data,
    'pending',
    TRUE
FROM loc
WHERE NULLIF(btrim(raw_source_data->>'Adresse'), '') IS NOT NULL
   OR NULLIF(btrim(raw_source_data->>'Code postal'), '') IS NOT NULL
   OR NULLIF(btrim(raw_source_data->>'Bureau postal'), '') IS NOT NULL
   OR gps IS NOT NULL;

INSERT INTO staging.object_description_temp (
    import_batch_id,
    staging_object_key,
    description,
    description_chapo,
    visibility,
    position,
    source_sheet,
    raw_source_data,
    resolution_status,
    is_approved
)
SELECT
    'old-data-berta2-all-20260501-01',
    raw_source_data->>'id',
    NULLIF(btrim(raw_source_data->>'Descriptif'), ''),
    NULLIF(btrim(raw_source_data->>'Accroche'), ''),
    'public',
    0,
    'Berta 2.0',
    raw_source_data,
    'pending',
    TRUE
FROM old_data_review_raw
WHERE NULLIF(btrim(raw_source_data->>'Descriptif'), '') IS NOT NULL
   OR NULLIF(btrim(raw_source_data->>'Accroche'), '') IS NOT NULL;

INSERT INTO staging.contact_channel_temp (
    import_batch_id,
    staging_object_key,
    kind_code,
    value,
    is_public,
    is_primary,
    position,
    source_sheet,
    raw_source_data,
    resolution_status,
    is_approved
)
SELECT
    'old-data-berta2-all-20260501-01',
    r.raw_source_data->>'id',
    c.kind_code,
    c.value,
    TRUE,
    c.is_primary,
    c.position,
    'Berta 2.0',
    r.raw_source_data,
    'pending',
    TRUE
FROM old_data_review_raw r
CROSS JOIN LATERAL (
    VALUES
        ('email', lower(btrim(r.raw_source_data->>'E-Mail')), TRUE, 0),
        ('phone', regexp_replace(COALESCE(r.raw_source_data->>'Fixe', ''), '[^0-9+]', '', 'g'), TRUE, 1),
        ('mobile', regexp_replace(COALESCE(r.raw_source_data->>'Mobile', ''), '[^0-9+]', '', 'g'), TRUE, 2),
        ('website', btrim(r.raw_source_data->>'Site web'), TRUE, 3)
) AS c(kind_code, value, is_primary, position)
WHERE NULLIF(c.value, '') IS NOT NULL
  AND (c.kind_code <> 'email' OR c.value ~* '^[A-Z0-9._%+\-]+@[A-Z0-9.\-]+\.[A-Z]{2,}$')
  AND (c.kind_code NOT IN ('phone', 'mobile') OR length(c.value) >= 6)
  AND (c.kind_code <> 'website' OR c.value ~* '^https?://')
ON CONFLICT (import_batch_id, staging_object_key, kind_code, value) DO NOTHING;
-- End supplemental review-mapped object rows.
COMMIT;
